## Implementation Steps

1. Add `computeCapacity` function to `src/domain/brp.ts`:
   - Input: `CapacityInputs`
   - Output: `CapacityResult`
   - Formula: gross = resources × spPerResource × sprintCount
   - holidayDeduction = holidayDays × resources (holidays hit everyone)
   - leaveDeduction = leaveDays (already total person-days)
   - total = max(0, gross - holidayDeduction - leaveDeduction)

2. Create `src/domain/brp.test.ts` with computeCapacity tests:
   - Worked example: 6 resources × 10 SP × 6 sprints = 360 gross, -12 holiday, -5 leave = 343
   - Edge case: negative total clamps to 0
   - Edge case: zero resources = 0 capacity
   - Edge case: large leave exceeds gross = 0

## Pseudo-code
```typescript
// src/domain/brp.ts
export function computeCapacity(inputs: CapacityInputs): CapacityResult {
  const gross = inputs.resources * inputs.spPerResource * inputs.sprintCount;
  const holidayDeduction = inputs.holidayDays * inputs.resources;
  const leaveDeduction = inputs.leaveDays;
  const total = Math.max(0, gross - holidayDeduction - leaveDeduction);
  return { gross, holidayDeduction, leaveDeduction, total };
}

// src/domain/brp.test.ts
import { describe, it, expect } from 'vitest';
import { computeCapacity } from './brp';

describe('computeCapacity', () => {
  it('computes PRD worked example: 6×10×6 - 12 - 5 = 343', () => {
    const result = computeCapacity({
      resources: 6, spPerResource: 10, sprintCount: 6,
      holidayDays: 2, leaveDays: 5
    });
    expect(result.total).toBe(343);
    expect(result.gross).toBe(360);
    expect(result.holidayDeduction).toBe(12);
    expect(result.leaveDeduction).toBe(5);
  });

  it('clamps negative total to 0', () => {
    const result = computeCapacity({
      resources: 1, spPerResource: 10, sprintCount: 1,
      holidayDays: 0, leaveDays: 100
    });
    expect(result.total).toBe(0);
  });
});
```

## Implementation Steps

1. Add `computeDelta` to `src/domain/brp.ts`:
   - Returns `frameResult.frameEstimate - humanEstimate`
   - Returns `null` if either side is missing

2. Add `computeVariance` to `src/domain/brp.ts`:
   - Step 1: If analysisStatus !== 'done' OR frameResult is null:
     - Return 'flagged' if description is thin (< 80 chars OR < 2 sentences)
     - Otherwise return 'pending'
   - Step 2: If computeDelta is null → return 'pending'
   - Step 3: Compute ratio = |delta| / max(humanEstimate, frameEstimate)
     - ratio ≤ 0.20 → 'agree'
     - ratio ≤ 0.50 → 'caution'
     - else → 're-groom'
   - Step 4: If band is 'agree' AND confidence < 0.40 → bump to 'caution'

3. Add tests to `src/domain/brp.test.ts`:
   - computeDelta null cases (no frameResult, no humanEstimate)
   - computeDelta positive/negative values
   - computeVariance 'pending' for raw epic
   - computeVariance 'flagged' for thin description
   - computeVariance exact threshold tests (0.20, 0.50)
   - computeVariance confidence bump at 0.40

## Pseudo-code
```typescript
export function computeDelta(epic: Epic): number | null {
  if (!epic.frameResult || epic.humanEstimate === null) return null;
  return epic.frameResult.frameEstimate - epic.humanEstimate;
}

export function computeVariance(epic: Epic): VarianceBand {
  // Step 1: Check analysis status
  if (epic.analysisStatus !== 'done' || !epic.frameResult) {
    const isThin = !epic.description || epic.description.length < 80;
    return isThin ? 'flagged' : 'pending';
  }
  // Step 2: Check delta
  const delta = computeDelta(epic);
  if (delta === null) return 'pending';
  // Step 3: Compute ratio
  const human = epic.humanEstimate!;
  const frame = epic.frameResult.frameEstimate;
  const ratio = Math.abs(delta) / Math.max(human, frame);
  let band: VarianceBand;
  if (ratio <= VARIANCE_AGREE_THRESHOLD) band = 'agree';
  else if (ratio <= VARIANCE_CAUTION_THRESHOLD) band = 'caution';
  else band = 're-groom';
  // Step 4: Confidence bump
  if (band === 'agree' && epic.frameResult.confidence < CONFIDENCE_BUMP_THRESHOLD) {
    band = 'caution';
  }
  return band;
}
```

