import type { GitLabConfig } from '@/domain/configTypes';
import type { Crew, Pod, Epic, ReferenceEpic, CapacityInputs } from '@/domain/brp';
import { fetchGitLabSubgroups, fetchGroupEpics } from '@/services/gitlab/gitlabClient';
import { DEFAULT_SP_PER_RESOURCE } from '@/domain/brp.constants';

type Result<T> = { success: true; data: T } | { success: false; error: string };

export async function fetchCrews(config: GitLabConfig): Promise<Result<Crew[]>> {
  const result = await fetchGitLabSubgroups(config, config.rootGroupId ?? '');
  if (!result.success) return { success: false, error: result.error ?? 'Failed to fetch crews' };

  const crews: Crew[] = (result.data ?? []).map(sg => ({
    id: String(sg.id),
    name: sg.name,
    gitlabGroupId: typeof sg.id === 'number' ? sg.id : parseInt(sg.id, 10),
    pods: [],
  }));
  return { success: true, data: crews };
}

export async function fetchPodEpics(config: GitLabConfig, podSubgroupId: number): Promise<Result<Epic[]>> {
  const result = await fetchGroupEpics(config, String(podSubgroupId));
  if (!result.success) return { success: false, error: result.error ?? 'Failed to fetch epics' };

  const epics: Epic[] = (result.data ?? []).map(e => ({
    id: String(e.id),
    iid: e.iid,
    title: e.title,
    gitlabWebUrl: e.web_url,
    podId: String(podSubgroupId),
    source: 'gitlab' as const,
    humanEstimate: null,  // NEVER pre-filled
    analysisStatus: 'raw' as const,  // ALWAYS 'raw'
    frameResult: null,  // NEVER pre-filled
  }));
  return { success: true, data: epics };
}
```

