export async function runAnalysisAction(abortSignal?: AbortSignal): Promise<void> {
  const store = useBrpStore.getState();
  const config = useConfigStore.getState().config;

  const estimator = getEstimator(config);
  const onError = (error: Error) => {
    useUiStore.getState().addToast({ type: 'error', title: error.message });
  };

  try {
    await store.runAnalysis(estimator, {
      onError,
      abortSignal,
      getReferences: (epicId) => brpService.fetchReferenceEpics(config.gitlab, epicId),
    });
  } catch (e) {
    onError(e instanceof Error ? e : new Error(String(e)));
  }
}

export async function handoffEpicToRefinementAction(epicId: string): Promise<void> {
  const epic = useBrpStore.getState().getEpic(epicId);
  if (!epic) return;

  // Write epic body to epicStore
  useEpicStore.getState().setMarkdown(epic.body);
  // Switch to planner tab
  useUiStore.getState().setActiveTab('planner');
  // Trigger existing pipeline
  await refinePipelineAction();
}
