export function checkUnrealisticCapacity(
  inputs: CapacityInputs,
  baseline?: { avgCapacityPerResource: number }
): string | null {
  const perResource = inputs.spPerResource * inputs.sprintsInPI;
  const threshold = (baseline?.avgCapacityPerResource ?? 50) * 1.5;
  if (perResource >= threshold) {
    return `Capacity of ${perResource} SP/resource exceeds 1.5× typical (${threshold} SP). Consider reviewing.`;
  }
  return null;
}
