import type { Epic } from '@/domain/brp';

export function interpretVariance(epic: Epic): string {
  if (!epic.frameResult) return 'Run Analysis to see FRAME interpretation.';

  const delta = (epic.frameEstimate ?? 0) - (epic.humanEstimate ?? 0);
  const breakdown = epic.frameResult.breakdown;

  switch (epic.variance) {
    case 'agree':
      return `FRAME agrees within tolerance. Breakdown: ${breakdown.join(', ')}.`;
    case 'caution':
      return `FRAME estimates ${delta > 0 ? '+' : ''}${delta} SP difference. Consider discussing scope.`;
    case 're-groom':
      return `Significant variance (${delta} SP). FRAME found ${breakdown.length} stories totaling ${epic.frameEstimate} SP.`;
    case 'flagged':
      return `Insufficient detail for reliable estimate. Add acceptance criteria.`;
    default:
      return 'Analysis pending.';
  }
}
