export function detectDuplicates(epics: Epic[], threshold = 0.7): Array<[string, string]> {
  const pairs: Array<[string, string]> = [];
  for (let i = 0; i < epics.length; i++) {
    for (let j = i + 1; j < epics.length; j++) {
      const similarity = jaccardSimilarity(tokenize(epics[i].title), tokenize(epics[j].title));
      if (similarity >= threshold) {
        pairs.push([epics[i].id, epics[j].id]);
      }
    }
  }
  return pairs;
}
