import { callAI } from '@/services/ai/aiClient';
import type { AIEstimator, AnalysisEvent, Epic } from '@/domain/brp';
import { FrameResultSchema } from './schemas';

export function createAzureOpenAIEstimator(config: AppConfig): AIEstimator {
  return {
    async *analyze(epic: Epic, references: Epic[]): AsyncIterable<AnalysisEvent> {
      yield { type: 'progress', epicId: epic.id, pct: 0 };

      try {
        const response = await callAI(buildConfig(config), {
          systemPrompt: buildSystemPrompt(),
          userPrompt: buildUserPrompt(epic, references),
          maxTokens: 2000,
        });

        // Parse and validate response
        const parsed = JSON.parse(response.content);
        const validated = FrameResultSchema.parse(parsed);

        yield { type: 'done', epicId: epic.id, result: validated };
      } catch (e) {
        yield { type: 'error', epicId: epic.id, message: e instanceof Error ? e.message : String(e) };
      }
    }
  };
}
```

Schema-validates every FrameResult before yielding. Invalid responses become error events. Gated live smoke test.

